uint64 pa_start;
struct spinlock memlock;

static uint64 pa2pgnm(void *pa) {
  if ((uint64)pa % PGSIZE != 0) {
    printf("pa %p\n", pa);
    panic("kfree!");
  }
  return ((uint64)pa - pa_start) / PGSIZE;
}

static void *pgnm2pa(int pgnm) {
  return (void *)((uint64)pgnm * PGSIZE + pa_start);
}

void kinit() {
  //多核情况下应该加锁
  initlock(&memlock, "memlock");
  buddysystem_init();
  // slab_init();
}

//从buddysystem中分配，需要额外的一步，从page num -> pa
void
kfree(void *pa)
{
  if ((uint64)pa == 1) {
    return ;
  }
  // acquire(&memlock);
  // memset(pa, 0, PGSIZE);
  buddyfree(bs, pa2pgnm(pa));
  // printf("free: %p\n", pa);
  // release(&memlock);
}

//从buddysystem中分配1页
void *
kalloc(void)
{
  // acquire(&memlock);
  int x = buddyalloc(bs, 0);
  void *pa = pgnm2pa(x);
  memset(pa, 0, PGSIZE);
  // release(&memlock);
  // printf("alloc:%p\n",pa);
  return pa;
}

static int size_to_page_num(uint64 size) {
  return size / PGSIZE + (size % PGSIZE != 0);
}

/*
 *TODO: 动态内存分配
 */
void *kmalloc(uint64 size) {
  int num = size_to_page_num(size);
  int x = buddyalloc(bs, num);
  void *pa = pgnm2pa(x);
  memset(pa, 0, num * PGSIZE);
  // printf("alloc:%p\n",pa);
  return pa;
}
void *kcalloc(uint n, uint64 size) {
  int num = size_to_page_num(size);
  int x = buddyalloc(bs, num);
  void *pa = pgnm2pa(x);
  memset(pa, 0, num * PGSIZE);
  // printf("alloc:%p\n",pa);
  return pa;
}

#include "mem/buddysystem.h"
#include "mem/memlayout.h"
#include "mem/kalloc.h"
#include "lib/string.h"
#include "lib/print.h"
#include "defs.h"

extern char end[]; // first address after kernel.
// defined by kernel.ld.

/*
 *通过一个类似线段树的类型对物理页号进行维护
 *log的复杂度完成一次页的分配和回收
 */
struct buddysystem *bs;


static int is_pow_of_2(uint32 x) {
    return !(x & (x-1));
}

static int next_pow_of_2(uint32 x) {
    if ( is_pow_of_2(x) )
        return x;
    x |= x>>1;
    x |= x>>2;
    x |= x>>4;
    x |= x>>8;
    x |= x>>16;
    return x+1;
}

static int _index_offset(int index, int level, int max_level) {
    return ((index + 1) - (1 << level)) << (max_level - level);
}


void buddysystem_init() {
    // pagen = next_pow_of_2((PHYSTOP - (uint64)end) / PGSIZE);
    pa_start = PGROUNDUP((uint64)end);
    bs = (struct buddysystem *)pa_start;
    pa_start += BSSIZE * PGSIZE;
    memset(bs, 0, BSSIZE * PGSIZE);
    while (!((1 << bs->level) & PGNUM)) bs->level++; //线段树有多少层
    // printf("pa_start: %p\n", pa_start);
}

static int index_offset(int index, int level, int max_level) {
    return ((index + 1) - (1 << level)) << (max_level - level);
}

static void mark_parent(struct buddysystem *self, int index) {
    while (1) {
        int buddy = index - 1 + (index & 1) * 2;
        if (buddy > 0 && (self->tree[buddy] == NODE_USED || self->tree[buddy] == NODE_FULL)) {
            index = (index + 1) / 2 - 1; //父节点
            self->tree[index] = NODE_FULL;
        } else {
            return ;
        }
    }
}

//从buddysystem中分配s个page
int buddyalloc(struct buddysystem *self, int s) {
    int size;
    if (s==0) {
        size = 1;
    } else {
        size = (int)next_pow_of_2(s);
    }
    int length = 1 << self->level;

    if (size > length)
        return -1;

    int index = 0;
    int level = 0;

    while (index >= 0) {
        if (size == length) {
            if (self->tree[index] == NODE_UNUSED) {
                self->tree[index] = NODE_USED;
                mark_parent(self, index);
                return _index_offset(index, level, self->level);
            }
        } else {
            // size < length
            switch (self->tree[index]) {
                case NODE_USED:
                case NODE_FULL:
                    break;
                case NODE_UNUSED:
                    // split first
                        self->tree[index] = NODE_SPLIT;
                self->tree[index*2+1] = NODE_UNUSED;
                self->tree[index*2+2] = NODE_UNUSED;
                default:
                    index = index * 2 + 1;
                length /= 2;
                level++;
                continue;
            }
        }
        if (index & 1) {
            ++index;
            continue;
        }
        for (;;) {
            level--;
            length *= 2;
            index = (index+1)/2 -1;
            if (index < 0)
                return -1;
            if (index & 1) {
                ++index;
                break;
            }
        }
    }

    return -1;
}

static void combine(struct buddysystem *self, int index) {
    while (1) {
        int buddy = index - 1 + (index & 1) * 2;
        if (buddy < 0 || self->tree[buddy] != NODE_UNUSED) {
            self->tree[index] = NODE_UNUSED;
            while (((index = (index + 1) / 2 - 1) >= 0) &&  self->tree[index] == NODE_FULL){
                self->tree[index] = NODE_SPLIT;
            }
            return ;
        }
        index = (index + 1) / 2 - 1;
    }
}

//回收一个page
void buddyfree(struct buddysystem *self, int offset) {
    int left = 0;
    int length = 1 << self->level;
    int index = 0;
    while (1) {
        switch (self->tree[index]) {
            case NODE_USED:
                combine(self, index);
                return ;
            case NODE_UNUSED:
                panic("Free wrong page");
                return ;
            default:
                length /= 2;
                if (offset < left + length) {
                    index = index * 2 + 1;
                } else {
                    left += length;
                    index = index * 2 + 2;
                }
                break;
        }
    }
}

#include "mem/slab.h"

#include "platform.h"

#include "mem/kalloc.h"

struct slab_cache *slab_cache[5];


static struct slab* get_owning_slab(void *pa) {
    return (struct slab *)PGROUNDDOWN((uint64)pa);
}

//对一个slab新分配的page进行
void page_free_obj_init(void *page, uint32 obj_size, uint64 page_end) {
    uint64 current_addr = (uint64)page;
    uint64 next_addr = (uint64)page + obj_size;
    for (;next_addr + obj_size < page_end; next_addr += obj_size,current_addr += obj_size) {
        *(uint64 *)current_addr = next_addr;
    }

    *(uint64 *)current_addr = 0;
}

//一个slab管理一个page
static struct slab *create_slab(uint32 obj_size) {
    struct slab *slab = kalloc();

    //为metadata预留空间
    int cnt = 1;
    while (cnt * obj_size <= sizeof(struct slab)) cnt++;

    list_init(&(slab->list));
    slab->pa_start = (void *)((uint64)slab + cnt * sizeof(struct slab)); //真正分配的内存
    uint64 page_end = (uint64)slab + PGSIZE;
    slab->free_objs_count = (PGSIZE - cnt * sizeof(struct slab)) / obj_size;
    slab->first_obj = (uint64)slab->pa_start;
    slab->max_objs_count = slab->free_objs_count;
    page_free_obj_init(slab->pa_start, obj_size, page_end);

    return slab;
}

static void destroy_slab(struct slab *slab) {
    kfree(slab);
}

static void *slab_alloc(struct slab *slab) {
    uint64 obj = slab->first_obj;
    slab->free_objs_count--;

    slab->first_obj = *(uint64 *)obj;

    return (void*)obj;
}

static void slab_free(struct slab *slab, void *obj) {
    slab->free_objs_count++;
    *(uint64 *)obj = slab->first_obj;
    slab->first_obj = (uint64)obj;
}

static void default_slab_memory_recycle(struct slab_cache *cache) {
    struct slab *slab;
    for (;cache->free_slabs_count > DEFAULT_MAX_FREE_SLABS_ALLOWED; cache->free_slabs_count--) {
        /*
         *这里能这样获得slab地址的方法基于slab的元数据放在page的起始地址
         *通过listhead的地址可以计算出来slab的首地址
         *如果一个slab管理超过一个页可能需要对这里的代码进行修改
         */
        slab = LIST2SLAB(cache->free_slabs.next);
        list_del(&(slab->list));
        destroy_slab(slab);
    }
}

struct slab_cache * slab_cache_new(uint32 size) {
    struct slab_cache *cache = kalloc();

    cache -> size = size;
    cache -> free_slabs_count = 0;

    list_init(&(cache->free_slabs));
    list_init(&(cache->partial_slabs));
    list_init(&(cache->full_slabs));
}

void *slab_cache_alloc(struct slab_cache *cache) {
    if (!list_empty(&(cache->partial_slabs))) {
        struct slab *slab = LIST2SLAB(cache->partial_slabs.next);

        void *pa = slab_alloc(slab);

        if (is_slab_full(slab)) {
            list_del(&(slab->list));
            list_add(&(slab->list), &(cache->full_slabs));
        }
        return pa;
    } else {
        //需要构造一个新的slab
        if (list_empty(&(cache->free_slabs))) {
            struct slab *slab = create_slab(cache->size);
            list_add(&(slab->list), &(cache->free_slabs));
            cache->free_slabs_count++;
        }
        //从free_slabs中分配内存
        struct slab *slab = LIST2SLAB(cache->free_slabs.next);
        void *pa = slab_alloc(slab);

        list_del(&(slab->list));
        list_add(&(slab->list), &(cache->partial_slabs));
    }
    return NULL;
}

void slab_cache_free(struct slab_cache *cache, void *pa) {
    struct slab *slab = get_owning_slab(pa);
    char slab_was_full = is_slab_full(slab);
    slab_free(slab, pa);
    char slab_now_empty = is_slab_empty(slab);

    if (!slab_was_full && slab_now_empty) {
        //partial -> free
        list_del(&(slab->list));
        list_add(&(slab->list), &(cache->free_slabs));
    } else if (slab_was_full) {
        //full -> partial
        list_del(&(slab->list));
        list_add(&(slab->list), &(cache->partial_slabs));
    }
    default_slab_memory_recycle(cache);
}

void slab_init() {
    slab_cache[0] = slab_cache_new(16);
    slab_cache[1] = slab_cache_new(32);
    slab_cache[2] = slab_cache_new(64);
    slab_cache[3] = slab_cache_new(128);
    slab_cache[4] = slab_cache_new(256);
}

int get_slab_cache_index(uint64 size) {
    if (size <= 16) {
        return 0;
    } else if (size <= 32) {
        return 1;
    } else if (size <= 64) {
        return 2;
    } else if (size <= 128) {
        return 3;
    } else if (size <= 256) {
        return 4;
    }
    return -1;
}

#include <dev/pci/pci.h>

#include "param.h"
