    kfree((void*)p->trapframe);

  p->trapframe = 0;
  if(p->pagetable)
    proc_freepagetable(p->pagetable, p->sz);

  p->pagetable = 0;
  p->sz = 0;
  p->pid = 0;
  p->parent = 0;
  p->name[0] = 0;
  p->chan = 0;
  p->killed = 0;
  p->xstate = 0;


  //Signal
  p->sig_frame = 0;
  p->block.val = 0;

  if (p->sig) {
    kfree(p->sig);
  }
  p->sig = 0;

  memset((void*)((p->kstack)), 0, PGSIZE);

  p->state = UNUSED;
}

