      absolute_path[n] = '/';
      absolute_path[n+1] = '\0';
      // printf("%s\n", absolute_path);
      r = vfs_ext_stat(absolute_path, &kbuf);
      if (r < 0) {
        // printf("fail");
        return r;
      }
    }

    if (copyout(myproc()->pagetable, st, (char*)(&kbuf), sizeof(kbuf)) < 0) {
      return -1;
    }
  }
  // printf("success\n");
  return 0;
}

