// Allocate a file structure.
struct file*
filealloc(void)
{
    struct file *f;

    acquire(&ftable.lock);
    for(f = ftable.file; f < ftable.file + NFILE; f++){
        if(f->f_count == 0){
            f->f_count = 1;
            release(&ftable.lock);
            return f;
        }
    }
    release(&ftable.lock);
    return 0;
}

// Increment ref count for file f.
struct file*
filedup(struct file *f)
{
    acquire(&ftable.lock);
    if(f->f_count < 1)
        panic("filedup");
    f->f_count++;
    release(&ftable.lock);
    return f;
}

// Close file f.  (Decrement ref count, close when reaches 0.)
void
fileclose(struct file *f)
{
    struct file ff;
    // printf("%s %d %d\n", f->f_path, f->f_type, f->f_count);

    acquire(&ftable.lock);
    if(f->f_count < 1)
        panic("fileclose");
    if(--f->f_count > 0){
        release(&ftable.lock);
        return;
    }
    ff = *f;
    f->f_count = 0;
    f->f_type = FD_NONE;
    release(&ftable.lock);

    if(ff.f_type == FD_PIPE){
        pipeclose(ff.f_pipe, get_fops()->writable(&ff));
    } else if(ff.f_type == FD_REG || ff.f_type == FD_DEVICE){
        /*
         *file中需要得到filesystem的类型
         *但是这里暂时只支持EXT4
         */
        if (vfs_ext_is_dir(ff.f_path) == 0) {
            vfs_ext_dirclose(&ff);
        } else {
            vfs_ext_fclose(&ff);
        }
        if (ff.removed) {
            vfs_ext_rm(ff.f_path);
            ff.removed = 0;
        }
    } else if (ff.f_type == FD_SOCKET) {
        socketclose(f->f_socket, f->f_socketnum);
        f->f_socketnum = -1;
        f->f_socketflags = 0;

    }
}

