struct inode *get_inode() {
    int i;
    acquire(&itable.lock);
    for(i = 0; i < NINODE; i++) {
        if (itable.inode[i].i_valid == 0) {
            itable.inode[i].i_valid = 1;
            break;
        }
    }
    release(&itable.lock);
    if (i == NINODE) {
        return NULL;
    }
    return &itable.inode[i];
}
