    int r = 0;
    struct ext4_file *file = (struct ext4_file *)f -> f_extfile;
    if (file == NULL) {
        panic("vfs_ext_ioctl: cannot get ext4 file\n");
    }

    switch (cmd) {
        case FIOCLEX:
            f->f_flags |= O_CLOEXEC;
        break;
        case FIONCLEX:
            f->f_flags &= ~O_CLOEXEC;
        break;
        case FIONREAD:
            r = ext4_fsize(file);
